(globalThis.TURBOPACK||(globalThis.TURBOPACK=[])).push(["object"==typeof document?document.currentScript:void 0,576626,n=>{"use strict";let t=[{id:"ko-scn-a1-greetings-001",level:"A1",situation:"greetings",title:{ko:"첫 만남 인사",en:"Meeting for the first time",zh:"初次见面问候",vi:"Lời chào khi gặp mặt lần đầu"},context:{ko:"새 동료와 처음 인사해요",en:"Greeting a new colleague for the first time",zh:"第一次和新同事打招呼",vi:"Chào hỏi đồng nghiệp mới lần đầu tiên"},turns:[{prompt:{ko:"안녕하세요! 처음 뵙겠습니다.",en:"Hello! Nice to meet you.",zh:"你好！初次见面。",vi:"Xin chào! Rất hân hạnh được gặp bạn lần đầu."},template:"안녕하세요, 저는 {0}.",blanks:[[{ko:"민수예요",en:"Minsu",zh:"是民洙",vi:"là Minsu"},{ko:"지은이에요",en:"Jieun",zh:"是智恩",vi:"là Jieun"}]],example:{ko:"안녕하세요, 저는 민수예요.",en:"Hello, I'm Minsu.",zh:"你好，我是民洙。",vi:"Xin chào, tôi là Minsu."}},{prompt:{ko:"만나서 반갑습니다. 어디에서 오셨어요?",en:"Nice to meet you. Where are you from?",zh:"很高兴认识你。你从哪里来？",vi:"Rất vui được gặp bạn. Bạn đến từ đâu?"},template:"저는 {0}에서 왔어요.",blanks:[[{ko:"미국",en:"the US",zh:"美国",vi:"Mỹ"},{ko:"영국",en:"the UK",zh:"英国",vi:"Anh"}]],example:{ko:"저는 미국에서 왔어요.",en:"I'm from the US.",zh:"我来自美国。",vi:"Tôi đến từ Mỹ."}},{prompt:{ko:"아, 그렇군요! 앞으로 잘 부탁해요.",en:"Oh, I see! I look forward to working with you.",zh:"啊，原来如此！以后请多关照。",vi:"À, ra vậy! Sau này mong được bạn giúp đỡ."},template:"네, 저도 잘 {0}.",blanks:[[{ko:"부탁드려요",en:"look forward to it (polite)",zh:"请多关照（礼貌）",vi:"mong được giúp đỡ (lịch sự)",note:"Common set phrase to close a greeting.",noteZh:"结束问候时常用的固定说法。",noteVi:"Cụm từ cố định thường dùng để kết thúc lời chào."},{ko:"부탁해요",en:"look forward to it",zh:"请多关照",vi:"mong được giúp đỡ",note:"Slightly more casual.",noteZh:"稍微更随意一些。",noteVi:"Hơi thân mật hơn một chút."}]],example:{ko:"네, 저도 잘 부탁드려요.",en:"Yes, I look forward to it too.",zh:"好的，我也请您多多关照。",vi:"Vâng, tôi cũng mong được bạn giúp đỡ."}}]},{id:"ko-scn-a1-food-001",level:"A1",situation:"food",title:{ko:"식당에서 주문하기",en:"Ordering at a restaurant",zh:"在餐厅点餐",vi:"Gọi món tại nhà hàng"},context:{ko:"식당에 들어가 음식을 주문하고 계산해요",en:"Entering a restaurant, ordering food, and paying",zh:"进入餐厅点餐并结账",vi:"Vào nhà hàng, gọi món và thanh toán"},turns:[{prompt:{ko:"어서 오세요! 몇 분이세요?",en:"Welcome! How many people?",zh:"欢迎光临！请问几位？",vi:"Xin chào quý khách! Quý khách đi mấy người ạ?"},template:"{0}이에요.",blanks:[[{ko:"두 명",en:"two people",zh:"两位",vi:"hai người"},{ko:"세 명",en:"three people",zh:"三位",vi:"ba người"}]],example:{ko:"두 명이에요.",en:"Two people.",zh:"两位。",vi:"Hai người ạ."}},{prompt:{ko:"여기 메뉴 있습니다. 주문하시겠어요?",en:"Here's the menu. Are you ready to order?",zh:"这是菜单。您要点餐了吗？",vi:"Đây là thực đơn ạ. Quý khách muốn gọi món chưa?"},template:"네, {0} 주세요.",blanks:[[{ko:"비빔밥 두 개",en:"two bibimbap",zh:"两份拌饭",vi:"hai phần cơm trộn bibimbap"},{ko:"불고기 하나",en:"one bulgogi",zh:"一份烤牛肉",vi:"một phần thịt bò nướng bulgogi"}]],example:{ko:"네, 비빔밥 두 개 주세요.",en:"Yes, two bibimbap, please.",zh:"好的，请给我两份拌饭。",vi:"Vâng, cho tôi hai phần cơm trộn bibimbap."}},{prompt:{ko:"맛있게 드셨어요?",en:"Did you enjoy your meal?",zh:"吃得还满意吗？",vi:"Quý khách dùng bữa có ngon miệng không ạ?"},template:"네, 정말 {0}.",blanks:[[{ko:"맛있었어요",en:"it was delicious",zh:"很好吃",vi:"rất ngon",note:"Past tense of 맛있어요.",noteZh:"맛있어요的过去式。",noteVi:"Dạng quá khứ của 맛있어요."},{ko:"잘 먹었어요",en:"I ate well (thank you for the meal)",zh:"我吃得很好（谢谢款待）",vi:"tôi đã ăn rất ngon (cảm ơn vì bữa ăn)",note:"Set phrase said after finishing a meal.",noteZh:"吃完饭后常说的固定用语。",noteVi:"Cụm từ cố định nói sau khi ăn xong."}]],example:{ko:"네, 정말 맛있었어요.",en:"Yes, it was really delicious.",zh:"是的，真的很好吃。",vi:"Vâng, thật sự rất ngon."}},{prompt:{ko:"계산은 어떻게 하시겠어요?",en:"How would you like to pay?",zh:"您想怎么结账？",vi:"Quý khách muốn thanh toán như thế nào ạ?"},template:"{0}.",blanks:[[{ko:"카드로 할게요",en:"I'll pay by card",zh:"我刷卡",vi:"tôi trả bằng thẻ",note:"로 marks the means of payment.",noteZh:"로表示付款方式。",noteVi:"로 đánh dấu phương thức thanh toán."},{ko:"현금으로 할게요",en:"I'll pay in cash",zh:"我付现金",vi:"tôi trả bằng tiền mặt",note:"현금 = cash. 으로 after a consonant.",noteZh:"현금即现金。辅音后用으로。",noteVi:"현금 nghĩa là tiền mặt. Dùng 으로 sau phụ âm."}]],example:{ko:"카드로 할게요.",en:"I'll pay by card.",zh:"我刷卡。",vi:"Tôi trả bằng thẻ."}}]},{id:"ko-scn-a1-self-intro-001",level:"A1",situation:"self-intro",title:{ko:"자기소개와 가족 이야기",en:"Introducing yourself and your family",zh:"自我介绍与家人介绍",vi:"Giới thiệu bản thân và gia đình"},context:{ko:"새 친구에게 나와 가족을 소개해요",en:"Introducing yourself and your family to a new friend",zh:"向新朋友介绍自己和家人",vi:"Giới thiệu bản thân và gia đình với một người bạn mới"},turns:[{prompt:{ko:"안녕하세요! 어디에서 오셨어요?",en:"Hello! Where are you from?",zh:"你好！你从哪里来？",vi:"Xin chào! Bạn đến từ đâu?"},template:"저는 {0}에서 왔어요.",blanks:[[{ko:"캐나다",en:"Canada",zh:"加拿大",vi:"Canada"},{ko:"호주",en:"Australia",zh:"澳大利亚",vi:"Úc"}]],example:{ko:"저는 캐나다에서 왔어요.",en:"I'm from Canada.",zh:"我来自加拿大。",vi:"Tôi đến từ Canada."}},{prompt:{ko:"그렇군요! 무슨 일 하세요?",en:"I see! What do you do for work?",zh:"原来如此！你做什么工作？",vi:"Ra vậy! Bạn làm nghề gì?"},template:"저는 {0}.",blanks:[[{ko:"학생이에요",en:"a student",zh:"是学生",vi:"là học sinh/sinh viên"},{ko:"회사원이에요",en:"an office worker",zh:"是公司职员",vi:"là nhân viên công ty"}]],example:{ko:"저는 학생이에요.",en:"I'm a student.",zh:"我是学生。",vi:"Tôi là sinh viên."}},{prompt:{ko:"가족은 몇 명이에요?",en:"How many people are in your family?",zh:"你家有几口人？",vi:"Gia đình bạn có mấy người?"},template:"{0}이에요. {1} 있어요.",blanks:[[{ko:"네 명",en:"four people",zh:"四个人",vi:"bốn người"},{ko:"세 명",en:"three people",zh:"三个人",vi:"ba người"}],[{ko:"여동생이 한 명",en:"one younger sister",zh:"一个妹妹",vi:"một em gái",note:"여동생 = younger sister.",noteZh:"여동생即妹妹。",noteVi:"여동생 nghĩa là em gái."},{ko:"남동생이 한 명",en:"one younger brother",zh:"一个弟弟",vi:"một em trai",note:"남동생 = younger brother.",noteZh:"남동생即弟弟。",noteVi:"남동생 nghĩa là em trai."}]],example:{ko:"네 명이에요. 여동생이 한 명 있어요.",en:"There are four of us. I have one younger sister.",zh:"是四个人。我有一个妹妹。",vi:"Là bốn người. Tôi có một em gái."}}]},{id:"ko-scn-a2-shopping-001",level:"A2",situation:"shopping",title:{ko:"옷 가게에서",en:"At a clothing store",zh:"在服装店",vi:"Ở cửa hàng quần áo"},context:{ko:"옷 가게에서 옷을 사요",en:"Buying clothes at a clothing store",zh:"在服装店买衣服",vi:"Mua quần áo ở cửa hàng quần áo"},turns:[{prompt:{ko:"어서 오세요. 뭐 찾으세요?",en:"Welcome. What are you looking for?",zh:"欢迎光临。您找什么？",vi:"Xin chào quý khách. Anh/chị tìm gì ạ?"},template:"{0} 보고 있어요.",blanks:[[{ko:"티셔츠를",en:"a T-shirt",zh:"T恤",vi:"áo phông"},{ko:"바지를",en:"pants",zh:"裤子",vi:"quần"}]],example:{ko:"티셔츠를 보고 있어요.",en:"I'm looking for a T-shirt.",zh:"我在看T恤。",vi:"Tôi đang xem áo phông."}},{prompt:{ko:"이건 어떠세요? 색깔도 예뻐요.",en:"How about this one? The color is pretty too.",zh:"这件怎么样？颜色也很漂亮。",vi:"Cái này thế nào ạ? Màu cũng đẹp nữa."},template:"예쁘네요. {0}?",blanks:[[{ko:"입어 봐도 돼요",en:"can I try it on",zh:"可以试穿吗",vi:"mặc thử được không",note:"-아/어 봐도 돼요? asks permission to try.",noteZh:"-아/어 봐도 돼요?用来请求试穿的许可。",noteVi:"-아/어 봐도 돼요? dùng để xin phép thử mặc."},{ko:"더 큰 거 있어요",en:"do you have a bigger one",zh:"有大一点的吗",vi:"có cái to hơn không",note:"더 큰 거 = a bigger one.",noteZh:"더 큰 거即“更大的”。",noteVi:"더 큰 거 nghĩa là 'cái to hơn'."}]],example:{ko:"예쁘네요. 입어 봐도 돼요?",en:"It's pretty. Can I try it on?",zh:"很漂亮。可以试穿吗？",vi:"Đẹp thật đấy. Tôi mặc thử được không?"}},{prompt:{ko:"잘 어울리세요! 이걸로 하시겠어요?",en:"It suits you! Would you like this one?",zh:"很适合您！您要这件吗？",vi:"Hợp với anh/chị lắm! Anh/chị có muốn lấy cái này không?"},template:"네, {0}. {1}?",blanks:[[{ko:"이걸로 할게요",en:"I'll take this one",zh:"我要这件",vi:"tôi lấy cái này",note:"States your choice.",noteZh:"表明你的选择。",noteVi:"Nói ra lựa chọn của bạn."},{ko:"이거 주세요",en:"please give me this",zh:"请给我这个",vi:"cho tôi cái này",note:"Simple and direct.",noteZh:"简单直接。",noteVi:"Đơn giản và trực tiếp."}],[{ko:"카드로 계산할 수 있어요",en:"can I pay by card",zh:"可以刷卡吗",vi:"có thể trả bằng thẻ không",note:"-(으)ㄹ 수 있어요? = is it possible?",noteZh:"-(으)ㄹ 수 있어요?意为“可以……吗？”。",noteVi:"-(으)ㄹ 수 있어요? nghĩa là 'có thể...không?'."},{ko:"얼마예요",en:"how much is it",zh:"多少钱",vi:"bao nhiêu tiền",note:"Ask the final price.",noteZh:"询问最终价格。",noteVi:"Hỏi giá cuối cùng."}]],example:{ko:"네, 이걸로 할게요. 카드로 계산할 수 있어요?",en:"Yes, I'll take this one. Can I pay by card?",zh:"好的，我要这件。可以刷卡吗？",vi:"Vâng, tôi lấy cái này. Tôi có thể trả bằng thẻ không?"}}]},{id:"ko-scn-a2-transport-001",level:"A2",situation:"transport",title:{ko:"지하철 길 찾기",en:"Finding your way on the subway",zh:"地铁问路",vi:"Tìm đường trên tàu điện ngầm"},context:{ko:"지하철역에서 길을 물어봐요",en:"Asking for directions at a subway station",zh:"在地铁站问路",vi:"Hỏi đường ở ga tàu điện ngầm"},turns:[{prompt:{ko:"무엇을 도와드릴까요?",en:"How can I help you?",zh:"有什么可以帮您的？",vi:"Tôi giúp gì được cho anh/chị ạ?"},template:"{0} 가고 싶어요. {1}?",blanks:[[{ko:"강남역에",en:"to Gangnam Station",zh:"到江南站",vi:"đến ga Gangnam"},{ko:"시청에",en:"to City Hall",zh:"到市厅",vi:"đến tòa thị chính"}],[{ko:"어떻게 가요",en:"how do I get there",zh:"怎么去",vi:"đi thế nào",note:"어떻게 = how.",noteZh:"어떻게即“怎么”。",noteVi:"어떻게 = thế nào."},{ko:"몇 호선을 타요",en:"which line do I take",zh:"坐几号线",vi:"đi tuyến số mấy",note:"호선 = subway line.",noteZh:"호선即地铁线路。",noteVi:"호선 = tuyến tàu điện ngầm."}]],example:{ko:"강남역에 가고 싶어요. 어떻게 가요?",en:"I want to go to Gangnam Station. How do I get there?",zh:"我想去江南站。怎么去？",vi:"Tôi muốn đến ga Gangnam. Đi thế nào ạ?"}},{prompt:{ko:"2호선을 타세요. 그런데 한 번 갈아타야 해요.",en:"Take line 2. But you have to transfer once.",zh:"请坐2号线。不过要换乘一次。",vi:"Hãy đi tuyến số 2. Nhưng phải chuyển tuyến một lần."},template:"{0}? 그리고 {1}?",blanks:[[{ko:"어디에서 갈아타요",en:"where do I transfer",zh:"在哪里换乘",vi:"chuyển tuyến ở đâu",note:"갈아타다 = to transfer.",noteZh:"갈아타다即换乘。",noteVi:"갈아타다 = chuyển tuyến."},{ko:"몇 정거장이에요",en:"how many stops is it",zh:"有几站",vi:"có mấy trạm",note:"정거장 = stop.",noteZh:"정거장即车站（站数）。",noteVi:"정거장 = trạm (số trạm)."}],[{ko:"얼마나 걸려요",en:"how long does it take",zh:"要多长时间",vi:"mất bao lâu",note:"걸리다 = to take time.",noteZh:"걸리다意为“花费时间”。",noteVi:"걸리다 nghĩa là 'mất thời gian'."},{ko:"표는 어디서 사요",en:"where do I buy a ticket",zh:"在哪里买票",vi:"mua vé ở đâu",note:"표 = ticket.",noteZh:"표即票。",noteVi:"표 = vé."}]],example:{ko:"어디에서 갈아타요? 그리고 얼마나 걸려요?",en:"Where do I transfer? And how long does it take?",zh:"在哪里换乘？还有要多长时间？",vi:"Chuyển tuyến ở đâu ạ? Và mất bao lâu?"}},{prompt:{ko:"사당역에서 갈아타시고, 약 삼십 분 걸려요.",en:"Transfer at Sadang Station, and it takes about 30 minutes.",zh:"在舍堂站换乘，大约要三十分钟。",vi:"Chuyển tuyến ở ga Sadang, và mất khoảng ba mươi phút."},template:"알겠어요. {0}.",blanks:[[{ko:"정말 감사합니다",en:"thank you very much",zh:"非常感谢",vi:"cảm ơn rất nhiều",note:"Polite thanks.",noteZh:"礼貌的感谢。",noteVi:"Lời cảm ơn lịch sự."},{ko:"도와주셔서 고맙습니다",en:"thanks for your help",zh:"谢谢您的帮助",vi:"cảm ơn vì đã giúp đỡ",note:"-아/어 주셔서 = for doing (for me).",noteZh:"-아/어 주셔서意为“（为我）做了……”。",noteVi:"-아/어 주셔서 nghĩa là '(vì đã) làm gì đó cho tôi'."}]],example:{ko:"알겠어요. 정말 감사합니다.",en:"Got it. Thank you very much.",zh:"知道了。非常感谢。",vi:"Vâng, tôi hiểu rồi. Cảm ơn rất nhiều."}}]},{id:"ko-scn-a2-time-date-001",level:"A2",situation:"time-date",title:{ko:"약속 정하기",en:"Making plans",zh:"约定计划",vi:"Lên kế hoạch hẹn gặp"},context:{ko:"친구와 만날 약속을 정해요",en:"Making plans to meet a friend",zh:"和朋友约定见面",vi:"Hẹn gặp bạn bè"},turns:[{prompt:{ko:"이번 주말에 시간 있어요? 같이 영화 봐요.",en:"Are you free this weekend? Let's watch a movie together.",zh:"这个周末有空吗？我们一起看电影吧。",vi:"Cuối tuần này bạn có rảnh không? Cùng xem phim nhé."},template:"좋아요! {0} 괜찮아요?",blanks:[[{ko:"토요일",en:"Saturday",zh:"星期六",vi:"thứ Bảy"},{ko:"일요일 오후",en:"Sunday afternoon",zh:"星期天下午",vi:"chiều Chủ nhật"}]],example:{ko:"좋아요! 토요일 괜찮아요?",en:"Great! Is Saturday okay?",zh:"好啊！星期六可以吗？",vi:"Được đó! Thứ Bảy được không?"}},{prompt:{ko:"네, 토요일 좋아요. 몇 시에 만날까요?",en:"Yes, Saturday is good. What time shall we meet?",zh:"好，星期六可以。我们几点见面？",vi:"Ừ, thứ Bảy được đấy. Mấy giờ mình gặp nhau nhỉ?"},template:"{0} 어때요? {1} 만나요.",blanks:[[{ko:"오후 두 시",en:"2 p.m.",zh:"下午两点",vi:"hai giờ chiều",note:"Hours use native numbers + 시.",noteZh:"“点”用固有数词加시。",noteVi:"Giờ dùng số đếm thuần Hàn + 시."},{ko:"저녁 여섯 시",en:"6 p.m.",zh:"晚上六点",vi:"sáu giờ tối",note:"저녁 = evening.",noteZh:"저녁即晚上。",noteVi:"저녁 = buổi tối."}],[{ko:"극장 앞에서",en:"in front of the theater",zh:"在电影院前面",vi:"trước rạp chiếu phim",note:"극장 = movie theater; 앞 = front.",noteZh:"극장即电影院；앞即前面。",noteVi:"극장 = rạp chiếu phim; 앞 = phía trước."},{ko:"지하철역에서",en:"at the subway station",zh:"在地铁站",vi:"ở ga tàu điện ngầm",note:"Easy meeting point.",noteZh:"方便的碰面地点。",noteVi:"Điểm hẹn thuận tiện."}]],example:{ko:"오후 두 시 어때요? 극장 앞에서 만나요.",en:"How about 2 p.m.? Let's meet in front of the theater.",zh:"下午两点怎么样？我们在电影院前面见。",vi:"Hai giờ chiều thế nào? Gặp nhau trước rạp chiếu phim nhé."}},{prompt:{ko:"좋아요. 그럼 토요일에 봐요!",en:"Sounds good. See you on Saturday then!",zh:"好的。那星期六见！",vi:"Được rồi. Vậy hẹn gặp vào thứ Bảy nhé!"},template:"네, {0}. {1}!",blanks:[[{ko:"이따 연락할게요",en:"I'll contact you later",zh:"我待会儿联系你",vi:"lát nữa tôi liên lạc nhé",note:"이따 = later (today); 연락하다 = to contact.",noteZh:"이따即“待会儿（今天晚些时候）”；연락하다即联系。",noteVi:"이따 = lát nữa (trong ngày hôm nay); 연락하다 = liên lạc."},{ko:"잊지 마세요",en:"don't forget",zh:"别忘了",vi:"đừng quên đấy",note:"잊다 = to forget.",noteZh:"잊다即忘记。",noteVi:"잊다 = quên."}],[{ko:"그때 봐요",en:"see you then",zh:"到时候见",vi:"hẹn gặp lúc đó",note:"그때 = at that time.",noteZh:"그때即“那时候”。",noteVi:"그때 = lúc đó."},{ko:"조심히 오세요",en:"come safely",zh:"路上小心",vi:"đi đường cẩn thận nhé",note:"Warm closing line.",noteZh:"温暖的结束语。",noteVi:"Lời kết ấm áp."}]],example:{ko:"네, 이따 연락할게요. 그때 봐요!",en:"Okay, I'll contact you later. See you then!",zh:"好，我待会儿联系你。到时候见！",vi:"Vâng, lát nữa tôi liên lạc nhé. Hẹn gặp lúc đó!"}}]},{id:"ko-scn-b1-work-001",level:"B1",situation:"work",title:{ko:"휴가 요청하기",en:"Asking for time off",zh:"请假",vi:"Xin nghỉ phép"},context:{ko:"팀장님께 휴가를 신청해요",en:"Requesting a day off from your team leader",zh:"向组长申请休假",vi:"Xin nghỉ phép với trưởng nhóm"},turns:[{prompt:{ko:"네, 들어오세요. 무슨 일이세요?",en:"Yes, come in. What can I do for you?",zh:"请进。有什么事吗？",vi:"Vâng, mời vào. Có việc gì vậy?"},template:"팀장님, 다음 주에 {0} 휴가를 {1}.",blanks:[[{ko:"개인적인 일로",en:"for personal reasons",zh:"因为私事",vi:"vì việc cá nhân"},{ko:"병원에 갈 일이 있어서",en:"because I have to go to the hospital",zh:"因为要去医院",vi:"vì tôi phải đi bệnh viện"}],[{ko:"하루 내고 싶어서요",en:"I'd like to take a day off",zh:"想请一天假",vi:"tôi muốn xin nghỉ một ngày",note:"휴가를 내다 = to put in for leave.",noteZh:"휴가를 내다 = 提出休假申请。",noteVi:"휴가를 내다 = nộp đơn xin nghỉ phép."},{ko:"쓰려고 하는데요",en:"I'm planning to use",zh:"打算休假",vi:"tôi định dùng phép",note:"휴가를 쓰다 = to use one's leave.",noteZh:"휴가를 쓰다 = 使用休假。",noteVi:"휴가를 쓰다 = sử dụng ngày phép."}]],example:{ko:"팀장님, 다음 주에 개인적인 일로 휴가를 하루 내고 싶어서요.",en:"Team leader, I'd like to take a day off next week for personal reasons.",zh:"组长，我下周因为私事想请一天假。",vi:"Trưởng nhóm ơi, tuần sau vì việc cá nhân tôi muốn xin nghỉ một ngày."}},{prompt:{ko:"아, 그래요? 무슨 요일을 생각하고 있어요?",en:"Oh, is that so? Which day are you thinking of?",zh:"哦，是吗？您想请哪天呢？",vi:"À, vậy à? Anh/chị đang định nghỉ ngày nào?"},template:"{0} 괜찮으면 {1} 쉬었으면 합니다.",blanks:[[{ko:"혹시",en:"if possible",zh:"如果方便的话",vi:"nếu có thể"},{ko:"가능하면",en:"if it's possible",zh:"可以的话",vi:"nếu được"}],[{ko:"수요일에",en:"on Wednesday",zh:"周三",vi:"vào thứ Tư"},{ko:"금요일에",en:"on Friday",zh:"周五",vi:"vào thứ Sáu"}]],example:{ko:"혹시 괜찮으면 수요일에 쉬었으면 합니다.",en:"If possible, I'd like to take Wednesday off.",zh:"如果方便的话，我想周三休息。",vi:"Nếu có thể, tôi muốn nghỉ vào thứ Tư."}},{prompt:{ko:"알겠어요. 그날 급한 일은 미리 정리해 두세요.",en:"All right. Just wrap up any urgent work beforehand.",zh:"好的。那天的急事请提前处理好。",vi:"Được rồi. Việc gấp hôm đó thì hãy xử lý trước nhé."},template:"네, {0}. {1}.",blanks:[[{ko:"그렇게 하겠습니다",en:"I'll do that",zh:"我会那样做的",vi:"tôi sẽ làm như vậy",note:"Polite, formal acceptance.",noteZh:"礼貌、正式的应允。",noteVi:"Sự chấp thuận lịch sự, trang trọng."},{ko:"미리 다 처리해 두겠습니다",en:"I'll take care of everything in advance",zh:"我会提前把一切都处理好",vi:"tôi sẽ xử lý hết mọi việc trước",note:"-아/어 두다 = do in advance and leave ready.",noteZh:"-아/어 두다 = 事先做好并保持就绪。",noteVi:"-아/어 두다 = làm trước và giữ ở trạng thái sẵn sàng."}],[{ko:"배려해 주셔서 감사합니다",en:"thank you for being considerate",zh:"谢谢您的体谅",vi:"cảm ơn sự quan tâm của anh/chị",note:"배려 = consideration/thoughtfulness.",noteZh:"배려 = 体谅／关照。",noteVi:"배려 = sự quan tâm/chu đáo."},{ko:"허락해 주셔서 감사합니다",en:"thank you for allowing it",zh:"谢谢您的批准",vi:"cảm ơn anh/chị đã cho phép",note:"허락하다 = to permit/allow.",noteZh:"허락하다 = 允许／批准。",noteVi:"허락하다 = cho phép/chấp thuận."}]],example:{ko:"네, 미리 다 처리해 두겠습니다. 배려해 주셔서 감사합니다.",en:"Yes, I'll take care of everything in advance. Thank you for being considerate.",zh:"好的，我会提前把一切都处理好。谢谢您的体谅。",vi:"Vâng, tôi sẽ xử lý hết mọi việc trước. Cảm ơn sự quan tâm của anh/chị."}}]},{id:"ko-scn-b1-health-001",level:"B1",situation:"health",title:{ko:"병원 진료",en:"A visit to the clinic",zh:"看病就诊",vi:"Khám bệnh ở phòng khám"},context:{ko:"감기 증상으로 병원에 가요",en:"Going to the clinic with cold symptoms",zh:"因感冒症状去医院",vi:"Đi khám vì triệu chứng cảm cúm"},turns:[{prompt:{ko:"안녕하세요, 어디가 불편해서 오셨어요?",en:"Hello, what brings you in today?",zh:"您好，您哪里不舒服来看诊呢？",vi:"Xin chào, anh/chị thấy khó chịu ở đâu mà đến khám vậy?"},template:"{0}부터 {1} 왔어요.",blanks:[[{ko:"이틀 전",en:"two days ago",zh:"两天前",vi:"hai ngày trước"},{ko:"어젯밤",en:"last night",zh:"昨晚",vi:"tối qua"}],[{ko:"열이 나고 기침이 심해서",en:"I've had a fever and a bad cough, so",zh:"发烧又咳嗽得厉害，所以",vi:"vì bị sốt và ho rất nặng",note:"-고 links two symptoms; -아/어서 gives the reason.",noteZh:"-고 连接两个症状；-아/어서 给出原因。",noteVi:"-고 nối hai triệu chứng; -아/어서 đưa ra lý do."},{ko:"목이 너무 아파서",en:"my throat hurts so much, so",zh:"嗓子太疼了，所以",vi:"vì họng đau quá",note:"너무 = too / very (intensifier).",noteZh:"너무 = 太／非常（强调词）。",noteVi:"너무 = quá/rất (từ nhấn mạnh)."}]],example:{ko:"이틀 전부터 열이 나고 기침이 심해서 왔어요.",en:"I came in because I've had a fever and a bad cough since two days ago.",zh:"我从两天前开始发烧又咳嗽得厉害，所以来了。",vi:"Từ hai ngày trước tôi bị sốt và ho rất nặng nên đến khám."}},{prompt:{ko:"목이 많이 부었네요. 혹시 다른 증상도 있으세요?",en:"Your throat is quite swollen. Do you have any other symptoms?",zh:"嗓子肿得挺厉害。还有其他症状吗？",vi:"Họng anh/chị sưng khá nặng. Có triệu chứng nào khác không?"},template:"네, {0} {1}.",blanks:[[{ko:"콧물도 나고",en:"I have a runny nose too, and",zh:"还流鼻涕",vi:"còn bị sổ mũi nữa"},{ko:"머리도 아프고",en:"I have a headache too, and",zh:"头也疼",vi:"đầu cũng đau nữa"}],[{ko:"온몸이 좀 쑤셔요",en:"my whole body aches a little",zh:"浑身有点酸痛",vi:"cả người hơi đau nhức",note:"쑤시다 = to ache/throb (muscles, joints).",noteZh:"쑤시다 = （肌肉、关节）酸痛／刺痛。",noteVi:"쑤시다 = đau nhức/nhói (cơ, khớp)."},{ko:"기운이 하나도 없어요",en:"I have no energy at all",zh:"一点力气都没有",vi:"không còn chút sức lực nào",note:"기운 = energy/strength; 하나도 없다 = none at all.",noteZh:"기운 = 精力／力气；하나도 없다 = 一点都没有。",noteVi:"기운 = năng lượng/sức lực; 하나도 없다 = không còn chút nào."}]],example:{ko:"네, 콧물도 나고 온몸이 좀 쑤셔요.",en:"Yes, I have a runny nose too, and my whole body aches a little.",zh:"是的，还流鼻涕，浑身也有点酸痛。",vi:"Vâng, còn bị sổ mũi nữa, cả người cũng hơi đau nhức."}},{prompt:{ko:"독감은 아니지만 몸살감기네요. 약 처방해 드릴게요.",en:"It's not the flu, but it's a bad cold. I'll prescribe you some medicine.",zh:"不是流感，不过是重感冒。我给您开点药。",vi:"Không phải cúm nhưng là cảm nặng đó. Tôi sẽ kê đơn thuốc cho anh/chị."},template:"감사합니다. 약은 {0} 먹으면 {1}?",blanks:[[{ko:"하루에 몇 번",en:"how many times a day",zh:"一天几次",vi:"một ngày mấy lần"},{ko:"언제",en:"when",zh:"什么时候",vi:"khi nào"}],[{ko:"될까요",en:"should I take it",zh:"合适呢",vi:"thì được ạ",note:"-(으)면 될까요 = a polite 'is it okay if...'.",noteZh:"-(으)면 될까요 = 礼貌的'这样可以吗'。",noteVi:"-(으)면 될까요 = cách hỏi lịch sự 'làm vậy có được không'."},{ko:"되나요",en:"is it okay",zh:"可以呢",vi:"thì có được không",note:"Slightly more neutral than 될까요.",noteZh:"比 될까요 略中性。",noteVi:"Trung tính hơn một chút so với 될까요."}]],example:{ko:"감사합니다. 약은 하루에 몇 번 먹으면 될까요?",en:"Thank you. How many times a day should I take the medicine?",zh:"谢谢。这药一天吃几次合适呢？",vi:"Cảm ơn bác sĩ. Thuốc này một ngày uống mấy lần thì được ạ?"}}]},{id:"ko-scn-b1-travel-001",level:"B1",situation:"travel",title:{ko:"호텔 체크인",en:"Checking in at a hotel",zh:"酒店办理入住",vi:"Nhận phòng khách sạn"},context:{ko:"예약한 호텔에 도착해 체크인해요",en:"Arriving at the hotel you booked and checking in",zh:"抵达预订的酒店并办理入住",vi:"Đến khách sạn đã đặt và làm thủ tục nhận phòng"},turns:[{prompt:{ko:"어서 오세요. 체크인 도와드릴까요?",en:"Welcome. May I help you check in?",zh:"欢迎光临。需要帮您办理入住吗？",vi:"Xin chào quý khách. Tôi giúp anh/chị nhận phòng nhé?"},template:"네, {0} {1} 있어요.",blanks:[[{ko:"오늘부터",en:"starting today",zh:"从今天起",vi:"từ hôm nay"},{ko:"이박 삼일로",en:"for two nights and three days",zh:"三天两夜",vi:"hai đêm ba ngày"}],[{ko:"예약했는데요. 이름은 김민수로 되어",en:"I have a reservation. It's under the name Kim Minsu",zh:"我预订了，登记的名字是金民秀",vi:"tôi đã đặt phòng rồi. Tên đăng ký là Kim Min-su",note:"-(으)로 되어 있다 = 'it's set/registered as'.",noteZh:"-(으)로 되어 있다 = '登记／注册为'。",noteVi:"-(으)로 되어 있다 = 'được đăng ký/thiết lập là'."},{ko:"방을 예약해 둔 게",en:"I have a room booked",zh:"我预订好了房间",vi:"tôi có đặt phòng trước rồi",note:"-아/어 두다 = booked in advance and kept.",noteZh:"-아/어 두다 = 提前预订并保留着。",noteVi:"-아/어 두다 = đặt trước và giữ nguyên."}]],example:{ko:"네, 오늘부터 예약했는데요. 이름은 김민수로 되어 있어요.",en:"Yes, I have a reservation starting today. It's under the name Kim Minsu.",zh:"是的，我预订了从今天起的房间。登记的名字是金民秀。",vi:"Vâng, tôi đã đặt phòng từ hôm nay. Tên đăng ký là Kim Min-su."}},{prompt:{ko:"확인됐습니다. 조식은 포함되어 있고, 체크아웃은 11시입니다.",en:"You're confirmed. Breakfast is included, and check-out is at 11.",zh:"已确认。含早餐，退房时间是11点。",vi:"Đã xác nhận rồi ạ. Có bao gồm bữa sáng, và giờ trả phòng là 11 giờ."},template:"감사합니다. 그런데 {0} {1}?",blanks:[[{ko:"조식은",en:"as for breakfast",zh:"早餐",vi:"bữa sáng thì"},{ko:"와이파이는",en:"as for the Wi-Fi",zh:"无线网络",vi:"wifi thì"}],[{ko:"몇 시부터 몇 시까지인가요",en:"from what time to what time is it",zh:"是从几点到几点呢",vi:"từ mấy giờ đến mấy giờ vậy",note:"부터...까지 = from...to (range).",noteZh:"부터……까지 = 从……到（范围）。",noteVi:"부터...까지 = từ...đến (khoảng thời gian)."},{ko:"어떻게 이용하면 되나요",en:"how do I use it",zh:"要怎么使用呢",vi:"sử dụng như thế nào ạ",note:"이용하다 = to use/make use of (facilities).",noteZh:"이용하다 = 使用／利用（设施）。",noteVi:"이용하다 = sử dụng/tận dụng (tiện nghi)."}]],example:{ko:"감사합니다. 그런데 조식은 몇 시부터 몇 시까지인가요?",en:"Thank you. By the way, from what time to what time is breakfast?",zh:"谢谢。对了，早餐是从几点到几点呢？",vi:"Cảm ơn. Mà bữa sáng từ mấy giờ đến mấy giờ vậy ạ?"}},{prompt:{ko:"조식은 7시부터 10시까지입니다. 더 궁금하신 점 있으세요?",en:"Breakfast is from 7 to 10. Is there anything else you'd like to know?",zh:"早餐是7点到10点。还有其他想了解的吗？",vi:"Bữa sáng từ 7 giờ đến 10 giờ ạ. Anh/chị còn muốn hỏi gì thêm không?"},template:"{0}. 이 근처에 {1} 추천해 주시겠어요?",blanks:[[{ko:"아, 알겠습니다",en:"ah, I see",zh:"啊，我知道了",vi:"À, tôi hiểu rồi"},{ko:"친절히 알려 주셔서 감사해요",en:"thank you for kindly explaining",zh:"谢谢您耐心告知",vi:"cảm ơn anh/chị đã nhiệt tình chỉ dẫn"}],[{ko:"가 볼 만한 곳 좀",en:"some places worth visiting",zh:"值得一去的地方",vi:"vài chỗ đáng đi tham quan",note:"-(으)ㄹ 만하다 = worth doing.",noteZh:"-(으)ㄹ 만하다 = 值得做。",noteVi:"-(으)ㄹ 만하다 = đáng để làm."},{ko:"괜찮은 식당 좀",en:"a decent restaurant",zh:"不错的餐厅",vi:"vài nhà hàng ngon",note:"좀 softens the request ('a little / please').",noteZh:"좀 使请求更委婉（'一点／麻烦'）。",noteVi:"좀 làm câu nhờ vả nhẹ nhàng hơn ('một chút/làm ơn')."}]],example:{ko:"아, 알겠습니다. 이 근처에 가 볼 만한 곳 좀 추천해 주시겠어요?",en:"Ah, I see. Could you recommend some places worth visiting nearby?",zh:"啊，我知道了。能推荐一下这附近值得一去的地方吗？",vi:"À, tôi hiểu rồi. Anh/chị có thể giới thiệu giúp vài chỗ đáng đi tham quan gần đây được không?"}}]},{id:"ko-scn-b2-opinion-001",level:"B2",situation:"opinion",title:{ko:"주 4일제 토론",en:"Debating a four-day workweek",zh:"四天工作制辩论",vi:"Tranh luận về chế độ làm việc 4 ngày/tuần"},context:{ko:"동료와 주 4일 근무제에 대해 의견을 나눠요",en:"Exchanging views with a colleague about a four-day workweek",zh:"和同事就四天工作制交换意见",vi:"Trao đổi ý kiến với đồng nghiệp về chế độ làm việc 4 ngày/tuần"},turns:[{prompt:{ko:"주 4일제 도입에 대해 어떻게 생각하세요?",en:"What do you think about introducing a four-day workweek?",zh:"您对引入四天工作制怎么看？",vi:"Bạn nghĩ sao về việc áp dụng chế độ làm việc 4 ngày một tuần?"},template:"저는 {0} 입장이에요.",blanks:[[{ko:"기본적으로 찬성하는",en:"basically in favor",zh:"基本上赞成",vi:"về cơ bản là ủng hộ",note:"기본적으로 = fundamentally/basically — hedges slightly.",noteZh:"기본적으로 = 基本上／根本上——略作保留。",noteVi:"기본적으로 = về cơ bản/về căn bản — có phần chừa đường lùi nhẹ."},{ko:"조심스럽게 반대하는",en:"cautiously opposed",zh:"谨慎地反对",vi:"thận trọng phản đối",note:"조심스럽게 = cautiously, softens a 반대 stance.",noteZh:"조심스럽게 = 谨慎地，缓和“반대（反对）”的立场。",noteVi:"조심스럽게 = một cách thận trọng, làm dịu lập trường 반대 (phản đối)."}]],example:{ko:"저는 기본적으로 찬성하는 입장이에요.",en:"I'm basically in favor.",zh:"我基本上持赞成的立场。",vi:"Về cơ bản tôi đứng về phía ủng hộ."}},{prompt:{ko:"그렇게 생각하는 이유가 뭐예요?",en:"What's your reason for thinking that?",zh:"您这么想的理由是什么？",vi:"Lý do bạn nghĩ như vậy là gì?"},template:"{0}, 그 이유는 {1} 때문이에요.",blanks:[[{ko:"솔직히 말하면",en:"to be honest",zh:"老实说",vi:"thành thật mà nói",note:"Signals a candid reason is coming.",noteZh:"预示接下来要说一个坦率的理由。",noteVi:"Báo hiệu sắp đưa ra một lý do thẳng thắn."},{ko:"제 경험상",en:"in my experience",zh:"以我的经验",vi:"theo kinh nghiệm của tôi",note:"경험상 = 'based on experience,' grounds the claim.",noteZh:"경험상 = “根据经验”，为主张提供依据。",noteVi:"경험상 = “dựa trên kinh nghiệm”, làm căn cứ cho lập luận."}],[{ko:"쉬는 날이 늘면 오히려 효율이 높아지기",en:"more rest days actually raise efficiency",zh:"休息日增多反而会提高效率",vi:"vì ngày nghỉ tăng lên ngược lại sẽ làm hiệu suất tăng",note:"오히려 = if anything; flags a counter-intuitive point.",noteZh:"오히려 = 反而；引出一个出人意料的观点。",noteVi:"오히려 = ngược lại/trái lại; đưa ra một quan điểm trái với dự đoán thông thường."},{ko:"삶의 질이 좋아지기",en:"quality of life improves",zh:"生活质量会变好",vi:"vì chất lượng cuộc sống được cải thiện",note:"삶의 질 = quality of life, a common B2 phrase.",noteZh:"삶의 질 = 生活质量，常用的 B2 短语。",noteVi:"삶의 질 = chất lượng cuộc sống, cụm từ thường dùng ở trình độ B2."}]],example:{ko:"솔직히 말하면, 그 이유는 쉬는 날이 늘면 오히려 효율이 높아지기 때문이에요.",en:"To be honest, the reason is that with more rest days, efficiency actually goes up.",zh:"老实说，理由是休息日增多反而会提高效率。",vi:"Thành thật mà nói, lý do là vì ngày nghỉ tăng lên thì ngược lại hiệu suất sẽ tăng."}},{prompt:{ko:"하지만 인건비 부담이 커지지 않을까요?",en:"But wouldn't labor costs become a bigger burden?",zh:"但人力成本的负担不会加重吗？",vi:"Nhưng gánh nặng chi phí nhân công chẳng phải sẽ tăng lên sao?"},template:"{0}, {1} 충분히 보완할 수 있다고 봐요.",blanks:[[{ko:"그 점도 일리가 있지만",en:"that point has merit too, but",zh:"那一点也有道理，但",vi:"điểm đó cũng có lý, nhưng",note:"Concedes the counterpoint diplomatically.",noteZh:"委婉地承认对方的反驳观点。",noteVi:"Thừa nhận một cách khéo léo quan điểm phản biện của đối phương."},{ko:"어느 정도 동의하지만",en:"I agree to an extent, but",zh:"在一定程度上同意，但",vi:"tôi đồng ý một phần, nhưng",note:"Partial agreement before rebutting.",noteZh:"在反驳之前先部分表示同意。",noteVi:"Đồng ý một phần trước khi đưa ra phản biện."}],[{ko:"생산성이 오르면",en:"if productivity rises",zh:"如果生产率提高",vi:"nếu năng suất tăng lên thì",note:"Conditional rebuttal tied to the earlier point.",noteZh:"与前面观点相呼应的条件式反驳。",noteVi:"Phản biện có điều kiện, hô ứng với quan điểm nêu trước đó."},{ko:"장기적으로 보면",en:"looking at it long-term",zh:"从长远来看",vi:"xét về lâu dài thì",note:"장기적으로 = in the long term — reframes the cost worry.",noteZh:"장기적으로 = 从长远看——重新审视成本方面的担忧。",noteVi:"장기적으로 = về lâu dài — nhìn lại mối lo về chi phí theo một góc độ khác."}]],example:{ko:"그 점도 일리가 있지만, 생산성이 오르면 충분히 보완할 수 있다고 봐요.",en:"That point has merit too, but if productivity rises, I think it can be sufficiently offset.",zh:"那一点也有道理，但我认为如果生产率提高，是完全可以弥补的。",vi:"Điểm đó cũng có lý, nhưng tôi cho rằng nếu năng suất tăng lên thì có thể bù đắp đầy đủ."}}]},{id:"ko-scn-b2-environment-001",level:"B2",situation:"environment",title:{ko:"일회용품 규제",en:"Single-use plastic rules",zh:"一次性用品管制",vi:"Quy định về đồ dùng một lần"},context:{ko:"카페에서 일회용품 규제에 대해 이야기해요",en:"Chatting about single-use plastic rules at a cafe",zh:"在咖啡店聊一次性用品的管制",vi:"Trò chuyện về quy định đồ dùng một lần tại quán cà phê"},turns:[{prompt:{ko:"요즘 카페에서 일회용 컵을 잘 안 주더라고요.",en:"These days cafes don't really give out disposable cups.",zh:"最近咖啡店都不太给一次性杯子了。",vi:"Dạo này quán cà phê không hay cho cốc dùng một lần nữa."},template:"맞아요, {0} 규제가 강화됐대요.",blanks:[[{ko:"환경 오염 때문에",en:"because of environmental pollution",zh:"因为环境污染",vi:"vì ô nhiễm môi trường",note:"환경 오염 = environmental pollution.",noteZh:"환경 오염 = 环境污染。",noteVi:"환경 오염 = ô nhiễm môi trường."},{ko:"일회용품을 줄이려고",en:"to cut down on disposables",zh:"为了减少一次性用品",vi:"để giảm đồ dùng một lần",note:"일회용품 = single-use items; 줄이다 = to reduce.",noteZh:"일회용품 = 一次性用品；줄이다 = 减少。",noteVi:"일회용품 = đồ dùng một lần; 줄이다 = giảm bớt."}]],example:{ko:"맞아요, 환경 오염 때문에 규제가 강화됐대요.",en:"Right, I heard the rules were tightened because of pollution.",zh:"对啊，听说因为环境污染，管制加强了。",vi:"Đúng vậy, nghe nói vì ô nhiễm môi trường nên quy định đã được siết chặt."}},{prompt:{ko:"조금 불편하긴 한데, 어떻게 생각해요?",en:"It's a bit inconvenient, but what do you think?",zh:"虽然有点不方便，你怎么看？",vi:"Có hơi bất tiện một chút, nhưng bạn nghĩ sao?"},template:"{0}, 저는 {1} 생각해요.",blanks:[[{ko:"불편한 건 사실이지만",en:"it's true it's inconvenient, but",zh:"不方便是事实，但",vi:"bất tiện thì đúng là sự thật, nhưng",note:"Concedes before giving a positive opinion.",noteZh:"在给出正面看法之前先让步。",noteVi:"Nhượng bộ trước khi đưa ra quan điểm tích cực."},{ko:"처음엔 어색했지만",en:"it was awkward at first, but",zh:"一开始不太习惯，但",vi:"lúc đầu thấy hơi ngượng, nhưng",note:"어색하다 = to feel awkward/unfamiliar.",noteZh:"어색하다 = 感到别扭／不习惯。",noteVi:"어색하다 = cảm thấy ngượng ngùng/chưa quen."}],[{ko:"꼭 필요한 변화라고",en:"that it's a necessary change",zh:"是一项必要的改变",vi:"là một sự thay đổi thực sự cần thiết",note:"꼭 필요하다 = absolutely necessary.",noteZh:"꼭 필요하다 = 绝对必要。",noteVi:"꼭 필요하다 = tuyệt đối cần thiết."},{ko:"장기적으로는 옳은 방향이라고",en:"that it's the right direction long-term",zh:"从长远看是正确的方向",vi:"về lâu dài là một hướng đi đúng đắn",note:"옳은 방향 = the right direction.",noteZh:"옳은 방향 = 正确的方向。",noteVi:"옳은 방향 = hướng đi đúng đắn."}]],example:{ko:"불편한 건 사실이지만, 저는 꼭 필요한 변화라고 생각해요.",en:"It's true it's inconvenient, but I think it's a necessary change.",zh:"不方便是事实，但我认为这是一项必要的改变。",vi:"Bất tiện thì đúng là sự thật, nhưng tôi nghĩ đây là một sự thay đổi thực sự cần thiết."}},{prompt:{ko:"그럼 개인적으로 실천하는 것도 있어요?",en:"So do you personally do anything about it?",zh:"那你个人有没有在践行什么呢？",vi:"Vậy cá nhân bạn có đang thực hành điều gì không?"},template:"네, {0} 들고 다니고, {1} 신경 쓰려고 해요.",blanks:[[{ko:"텀블러를",en:"a tumbler",zh:"随行杯",vi:"bình giữ nhiệt cá nhân",note:"텀블러 = reusable tumbler — very common in Korea.",noteZh:"텀블러 = 可重复使用的随行杯——在韩国很常见。",noteVi:"텀블러 = bình/ly cá nhân dùng nhiều lần — rất phổ biến ở Hàn Quốc."},{ko:"장바구니를",en:"a shopping bag",zh:"购物袋",vi:"túi đi chợ",note:"장바구니 = reusable shopping bag.",noteZh:"장바구니 = 可重复使用的购物袋。",noteVi:"장바구니 = túi đi chợ có thể dùng lại nhiều lần."}],[{ko:"분리수거에도",en:"to sorting recycling too",zh:"对垃圾分类也",vi:"cả việc phân loại rác nữa",note:"분리수거 = separating recycling.",noteZh:"분리수거 = 垃圾分类回收。",noteVi:"분리수거 = phân loại rác để tái chế."},{ko:"친환경 제품에도",en:"to eco-friendly products too",zh:"对环保产品也",vi:"cả sản phẩm thân thiện môi trường nữa",note:"친환경 = eco-friendly.",noteZh:"친환경 = 环保。",noteVi:"친환경 = thân thiện với môi trường."}]],example:{ko:"네, 텀블러를 들고 다니고, 분리수거에도 신경 쓰려고 해요.",en:"Yes, I carry a tumbler around and try to be careful about sorting recycling too.",zh:"嗯，我会随身带着随行杯，也尽量注意垃圾分类。",vi:"Vâng, tôi mang theo bình giữ nhiệt cá nhân, và cũng cố gắng chú ý đến việc phân loại rác."}}]},{id:"ko-scn-b2-technology-001",level:"B2",situation:"technology",title:{ko:"AI와 일자리",en:"AI and jobs",zh:"AI 与就业",vi:"AI và việc làm"},context:{ko:"친구와 인공지능이 일자리에 미치는 영향을 이야기해요",en:"Talking with a friend about how AI affects jobs",zh:"和朋友聊人工智能对就业的影响",vi:"Nói chuyện với bạn về ảnh hưởng của trí tuệ nhân tạo đến việc làm"},turns:[{prompt:{ko:"요즘 인공지능 때문에 일자리 걱정하는 사람이 많더라고요.",en:"A lot of people are worried about jobs because of AI these days.",zh:"最近因为人工智能而担心工作的人很多。",vi:"Dạo này có nhiều người lo lắng về việc làm vì trí tuệ nhân tạo."},template:"그러게요, {0} 분위기예요.",blanks:[[{ko:"불안해하는",en:"feeling anxious",zh:"感到不安",vi:"cảm thấy bất an",note:"불안해하다 = to feel uneasy/anxious.",noteZh:"불안해하다 = 感到不安／焦虑。",noteVi:"불안해하다 = cảm thấy bất an/lo lắng."},{ko:"변화를 실감하는",en:"really feeling the change",zh:"切实感受到变化",vi:"cảm nhận rõ sự thay đổi",note:"실감하다 = to feel something as real/tangible.",noteZh:"실감하다 = 真切地感受到某事。",noteVi:"실감하다 = cảm nhận điều gì đó một cách chân thực/rõ ràng."}]],example:{ko:"그러게요, 불안해하는 분위기예요.",en:"Yeah, there's an anxious mood.",zh:"就是说啊，弥漫着一种不安的气氛。",vi:"Đúng vậy, không khí đang khá bất an."}},{prompt:{ko:"정말 사람을 다 대체하게 될까요?",en:"Will it really end up replacing everyone?",zh:"真的会把人全都取代掉吗？",vi:"Liệu nó có thực sự thay thế hết tất cả mọi người không?"},template:"{0}, {1} 거라고 봐요.",blanks:[[{ko:"제 생각에는",en:"in my opinion",zh:"在我看来",vi:"theo tôi nghĩ",note:"Neutral opinion frame.",noteZh:"中性的观点表达框架。",noteVi:"Cách trình bày quan điểm mang tính trung lập."},{ko:"엄밀히 따지면",en:"strictly speaking",zh:"严格来说",vi:"xét cho kỹ thì",note:"엄밀히 따지면 = makes a careful distinction.",noteZh:"엄밀히 따지면 = 做出审慎的区分。",noteVi:"엄밀히 따지면 = đưa ra một sự phân biệt cẩn trọng."}],[{ko:"완전히 대체하기보다는 역할이 바뀌는",en:"roles will change rather than be fully replaced",zh:"与其说是完全取代，不如说角色会转变",vi:"vai trò sẽ thay đổi chứ không phải bị thay thế hoàn toàn",note:"대체하다 = replace; reframes 'replace' as 'shift.'",noteZh:"대체하다 = 取代；把“取代”重新诠释为“转变”。",noteVi:"대체하다 = thay thế; diễn giải lại “thay thế” thành “chuyển đổi”."},{ko:"오히려 새로운 일자리도 생길",en:"new jobs will appear, if anything",zh:"反而还会出现新的工作岗位",vi:"ngược lại sẽ còn xuất hiện việc làm mới",note:"오히려 = if anything — a counter-intuitive turn.",noteZh:"오히려 = 反而——出人意料的转折。",noteVi:"오히려 = ngược lại — một bước ngoặt trái với dự đoán."}]],example:{ko:"제 생각에는, 완전히 대체하기보다는 역할이 바뀌는 거라고 봐요.",en:"In my opinion, roles will change rather than being fully replaced.",zh:"在我看来，与其说是完全取代，不如说角色会发生转变。",vi:"Theo tôi nghĩ, vai trò sẽ thay đổi chứ không phải bị thay thế hoàn toàn."}},{prompt:{ko:"그래도 부작용은 좀 걱정되지 않아요?",en:"Still, aren't you a bit worried about the downsides?",zh:"不过副作用你就不担心一点吗？",vi:"Nhưng bạn không lo lắng một chút về tác dụng phụ sao?"},template:"{0}. 특히 {1} 점이 걱정돼요.",blanks:[[{ko:"그 부분은 저도 공감해요",en:"I share that concern",zh:"这一点我也有同感",vi:"phần đó tôi cũng đồng cảm",note:"공감하다 = to empathize/relate to.",noteZh:"공감하다 = 有同感／产生共鸣。",noteVi:"공감하다 = đồng cảm/thấu hiểu."},{ko:"그 점은 분명히 짚어야 해요",en:"that point definitely needs addressing",zh:"那一点确实需要点明",vi:"điểm đó chắc chắn cần phải chỉ rõ ra",note:"짚다 = to point out/pinpoint an issue.",noteZh:"짚다 = 指出／点明问题。",noteVi:"짚다 = chỉ ra/nêu rõ một vấn đề."}],[{ko:"기술에 지나치게 의존하게 되는",en:"becoming overly reliant on technology",zh:"变得过度依赖技术",vi:"trở nên phụ thuộc quá mức vào công nghệ",note:"...에 의존하다 = to depend on; 지나치게 = excessively.",noteZh:"……에 의존하다 = 依赖；지나치게 = 过度地。",noteVi:"...에 의존하다 = phụ thuộc vào; 지나치게 = một cách quá mức."},{ko:"정보 격차가 더 벌어지는",en:"the information gap widening further",zh:"信息鸿沟进一步拉大",vi:"khoảng cách thông tin ngày càng nới rộng",note:"정보 격차 = the digital divide; 벌어지다 = to widen.",noteZh:"정보 격차 = 数字鸿沟；벌어지다 = 拉大／扩大。",noteVi:"정보 격차 = khoảng cách số; 벌어지다 = nới rộng/mở rộng."}]],example:{ko:"그 부분은 저도 공감해요. 특히 기술에 지나치게 의존하게 되는 점이 걱정돼요.",en:"I share that concern. I'm especially worried about becoming overly reliant on technology.",zh:"这一点我也有同感。我尤其担心变得过度依赖技术这一点。",vi:"Phần đó tôi cũng đồng cảm. Tôi đặc biệt lo lắng về việc trở nên phụ thuộc quá mức vào công nghệ."}}]},{id:"ko-scn-c1-business-001",level:"C1",situation:"business",title:{ko:"예산 협상 회의",en:"Budget negotiation meeting",zh:"预算谈判会议",vi:"Cuộc họp đàm phán ngân sách"},context:{ko:"거래처와 예산·일정을 조율하는 회의",en:"A meeting to align budget and schedule with a client",zh:"与客户协调预算和日程的会议",vi:"Cuộc họp điều chỉnh ngân sách và tiến độ với đối tác"},turns:[{prompt:{ko:"제안하신 견적이 예상보다 높습니다. 조정이 가능할까요?",en:"The quote you proposed is higher than expected. Is an adjustment possible?",zh:"您提出的报价比预期高。能否调整一下？",vi:"Báo giá mà quý vị đề xuất cao hơn dự kiến. Liệu có thể điều chỉnh được không?"},template:"말씀 이해합니다. {0} 일부 항목은 {1} 여지가 있습니다.",blanks:[[{ko:"범위를 조정하면",en:"if we adjust the scope",zh:"如果调整范围",vi:"nếu điều chỉnh phạm vi",note:"Trades scope for cost — a classic negotiation lever.",noteZh:"以范围换成本——经典的谈判筹码。",noteVi:"Đánh đổi phạm vi lấy chi phí — một đòn bẩy đàm phán kinh điển."},{ko:"물량을 늘리면",en:"if you increase the volume",zh:"如果增加数量",vi:"nếu tăng số lượng",note:"물량 (quantity/volume, 物量) — offers a volume discount angle.",noteZh:"물량（数量、物量，物量）——提供以量换价的思路。",noteVi:"물량 (số lượng, khối lượng) — gợi ý hướng chiết khấu theo số lượng."}],[{ko:"절감할",en:"to cut down",zh:"削减",vi:"cắt giảm",note:"절감하다 (to reduce, 節減) — formal for trimming cost.",noteZh:"절감하다（节减，節減）——削减成本的正式说法。",noteVi:"절감하다 (tiết giảm) — cách nói trang trọng để chỉ việc cắt giảm chi phí."},{ko:"재검토할",en:"to reconsider",zh:"重新研究",vi:"xem xét lại",note:"재검토 (re-review, 再檢討) — leaves room without committing.",noteZh:"재검토（重新研究，再檢討）——留有余地而不作承诺。",noteVi:"재검토 (xem xét lại) — để lại khoảng trống mà không cam kết chắc chắn."}]],example:{ko:"말씀 이해합니다. 범위를 조정하면 일부 항목은 절감할 여지가 있습니다.",en:"I understand. If we adjust the scope, there's room to cut down some line items.",zh:"我理解您的意思。如果调整范围，部分项目还有削减的余地。",vi:"Tôi hiểu ý quý vị. Nếu điều chỉnh phạm vi thì một số hạng mục vẫn còn chỗ để cắt giảm."}},{prompt:{ko:"그렇다면 일정도 함께 앞당길 수 있습니까?",en:"In that case, can the schedule also be moved up?",zh:"那样的话，日程也能一并提前吗？",vi:"Nếu vậy thì tiến độ cũng có thể đẩy sớm lên được không?"},template:"일정은 {0} 어렵지만, {1} 단계적으로 진행한다면 {2}.",blanks:[[{ko:"무리하게 앞당기기는",en:"to force it earlier",zh:"勉强提前",vi:"việc gượng ép đẩy sớm lên",note:"무리하게 = unreasonably/forcibly. Signals a realistic limit.",noteZh:"무리하게 = 勉强地、硬来地。表明现实的限度。",noteVi:"무리하게 = một cách gượng ép, quá sức. Cho thấy giới hạn thực tế."},{ko:"전체를 단축하기는",en:"to shorten the whole thing",zh:"缩短整体",vi:"việc rút ngắn toàn bộ",note:"단축하다 (to shorten, 短縮) — addresses the timeline directly.",noteZh:"단축하다（缩短，短縮）——直接针对时间安排。",noteVi:"단축하다 (rút ngắn) — nhắm trực tiếp vào việc bố trí thời gian."}],[{ko:"핵심 기능부터",en:"starting with the core features",zh:"从核心功能开始",vi:"bắt đầu từ các tính năng cốt lõi",note:"Prioritizes high-value deliverables first.",noteZh:"优先交付高价值的部分。",noteVi:"Ưu tiên bàn giao trước những phần có giá trị cao."},{ko:"우선순위를 정해",en:"by setting priorities",zh:"确定优先次序",vi:"bằng cách xác định thứ tự ưu tiên",note:"우선순위 (priority, 優先順位) — structured phasing.",noteZh:"우선순위（优先次序，優先順位）——有条理地分阶段推进。",noteVi:"우선순위 (thứ tự ưu tiên) — triển khai theo từng giai đoạn một cách có hệ thống."}],[{ko:"가능할 것 같습니다",en:"it should be possible",zh:"应该是可行的",vi:"chắc là có thể được",note:"Polite conditional offer that keeps the deal moving.",noteZh:"礼貌的有条件承诺，让交易得以继续推进。",noteVi:"Một đề nghị có điều kiện, lịch sự, giúp thương vụ tiếp tục tiến triển."},{ko:"맞춰 보겠습니다",en:"I'll try to accommodate",zh:"我会尽量配合",vi:"tôi sẽ cố gắng thu xếp cho phù hợp",note:"맞추다 = to align/accommodate. Cooperative tone.",noteZh:"맞추다 = 配合、迁就。语气合作。",noteVi:"맞추다 = điều chỉnh cho khớp, thu xếp phù hợp. Giọng điệu hợp tác."}]],example:{ko:"일정은 무리하게 앞당기기는 어렵지만, 핵심 기능부터 단계적으로 진행한다면 가능할 것 같습니다.",en:"Forcing the schedule earlier is difficult, but if we proceed in stages starting with the core features, it should be possible.",zh:"日程要勉强提前有难度，但如果从核心功能开始分阶段推进，应该是可行的。",vi:"Việc gượng ép đẩy sớm tiến độ thì khó, nhưng nếu triển khai theo từng giai đoạn bắt đầu từ các tính năng cốt lõi thì chắc là có thể được."}},{prompt:{ko:"좋습니다. 그럼 세부 조건은 어떻게 확정하면 될까요?",en:"Good. Then how should we finalize the detailed terms?",zh:"好的。那么细节条款该如何敲定呢？",vi:"Tốt. Vậy các điều khoản chi tiết thì nên chốt như thế nào?"},template:"오늘 논의를 바탕으로 {0} 정리해서, {1} 다시 {2}.",blanks:[[{ko:"합의된 사항을",en:"the agreed points",zh:"已达成一致的事项",vi:"những nội dung đã thống nhất",note:"합의 (agreement, 合意) — consolidates what's settled.",noteZh:"합의（合意、共识，合意）——把已定下的内容归拢起来。",noteVi:"합의 (thỏa thuận, đồng thuận) — tổng hợp lại những gì đã được chốt."},{ko:"수정 견적을",en:"a revised quote",zh:"修改后的报价",vi:"bản báo giá đã chỉnh sửa",note:"Concrete next deliverable from the negotiation.",noteZh:"谈判后要交付的具体成果。",noteVi:"Kết quả cụ thể tiếp theo cần bàn giao sau đàm phán."}],[{ko:"후속 미팅에서",en:"in a follow-up meeting",zh:"在后续会议上",vi:"trong cuộc họp tiếp theo",note:"후속 (follow-up, 後續) — schedules the next touchpoint.",noteZh:"후속（后续，後續）——安排下一次沟通。",noteVi:"후속 (tiếp theo, kế tiếp) — sắp xếp điểm liên lạc kế tiếp."},{ko:"다음 주 중으로",en:"sometime next week",zh:"下周之内",vi:"trong khoảng tuần sau",note:"Gives a concrete, polite timeframe.",noteZh:"给出具体而礼貌的时间范围。",noteVi:"Đưa ra một khung thời gian cụ thể và lịch sự."}],[{ko:"확정하시죠",en:"let's finalize",zh:"就此敲定吧",vi:"hãy chốt lại",note:"확정하다 (to confirm/finalize, 確定) — decisive close.",noteZh:"확정하다（确定、敲定，確定）——果断收尾。",noteVi:"확정하다 (xác định, chốt) — kết thúc một cách dứt khoát."},{ko:"검토하시죠",en:"let's review",zh:"再研究一下吧",vi:"hãy xem xét lại",note:"Slightly softer, leaves a final check.",noteZh:"语气略柔和，留一次最终确认。",noteVi:"Giọng điệu nhẹ nhàng hơn, để lại một bước kiểm tra cuối cùng."}]],example:{ko:"오늘 논의를 바탕으로 합의된 사항을 정리해서, 후속 미팅에서 다시 확정하시죠.",en:"Based on today's discussion, let's organize the agreed points and finalize them in a follow-up meeting.",zh:"以今天的讨论为基础，把已达成一致的事项整理好，在后续会议上再敲定吧。",vi:"Dựa trên những gì đã thảo luận hôm nay, hãy tổng hợp lại những nội dung đã thống nhất, rồi chốt lại một lần nữa trong cuộc họp tiếp theo."}}]},{id:"ko-scn-c1-society-001",level:"C1",situation:"society",title:{ko:"사회 이슈 토론",en:"Debating a social issue",zh:"社会议题辩论",vi:"Tranh luận về vấn đề xã hội"},context:{ko:"고령화와 세대 갈등을 두고 의견을 나누는 토론",en:"A discussion sharing views on aging and generational conflict",zh:"围绕老龄化与世代矛盾交换意见的讨论",vi:"Cuộc thảo luận trao đổi quan điểm về già hóa dân số và xung đột thế hệ"},turns:[{prompt:{ko:"요즘 세대 갈등이 심하다고 하는데, 어떻게 생각하세요?",en:"They say generational conflict is severe these days — what do you think?",zh:"听说最近世代矛盾很严重，您怎么看？",vi:"Nghe nói dạo này xung đột thế hệ khá nghiêm trọng, anh/chị nghĩ sao?"},template:"{0} 문제지만, 갈등 자체보다 {1} 부족이 더 근본적이라고 봅니다.",blanks:[[{ko:"분명히 짚고 넘어가야 할",en:"definitely worth addressing",zh:"确实值得点明并正视的",vi:"chắc chắn cần phải chỉ ra",note:"짚고 넘어가다 = to address before moving on. Measured acknowledgment.",noteZh:"짚고 넘어가다 = 在继续之前先加以指出。表示有分寸的认可。",noteVi:"짚고 넘어가다 = nêu ra rồi mới tiếp tục. Thể hiện sự thừa nhận có chừng mực."},{ko:"사회적으로 대두된",en:"that has emerged socially",zh:"在社会上凸显出来的",vi:"đã nổi lên trong xã hội",note:"대두되다 (to come to the fore, 擡頭) — frames it as a rising issue.",noteZh:"대두되다（抬头、凸显，擡頭）——将其定位为日益突出的问题。",noteVi:"대두되다 (ngóc đầu dậy, nổi lên) — định vị đây là một vấn đề đang ngày càng nổi cộm."}],[{ko:"소통의",en:"of communication",zh:"沟通的",vi:"về giao tiếp",note:"소통 (communication, 疏通) — points to the deeper cause.",noteZh:"소통（沟通，疏通）——指向更深层的原因。",noteVi:"소통 (giao tiếp, thông hiểu) — chỉ ra nguyên nhân sâu xa hơn."},{ko:"상호 이해의",en:"of mutual understanding",zh:"相互理解的",vi:"về sự thấu hiểu lẫn nhau",note:"상호 (mutual, 相互) — frames it as a two-way gap.",noteZh:"상호（相互，相互）——将其视为双向的隔阂。",noteVi:"상호 (lẫn nhau, tương hỗ) — coi đây là khoảng cách mang tính hai chiều."}]],example:{ko:"분명히 짚고 넘어가야 할 문제지만, 갈등 자체보다 소통의 부족이 더 근본적이라고 봅니다.",en:"It's definitely an issue worth addressing, but rather than the conflict itself, the lack of communication is more fundamental.",zh:"这确实是个值得正视的问题，但比起矛盾本身，沟通的缺乏才更为根本。",vi:"Đây chắc chắn là vấn đề cần phải chỉ ra, nhưng tôi cho rằng sự thiếu hụt trong giao tiếp mới là gốc rễ, hơn cả bản thân xung đột."}},{prompt:{ko:"하지만 고령화까지 겹치면 갈등이 더 커지지 않을까요?",en:"But if aging is added on top, won't the conflict grow even worse?",zh:"但如果再加上老龄化，矛盾不会变得更大吗？",vi:"Nhưng nếu cộng thêm cả tình trạng già hóa dân số thì xung đột chẳng phải sẽ càng lớn hơn sao?"},template:"역으로 보면, 고령화는 {0} 세대가 {1} 계기가 될 수도 있습니다.",blanks:[[{ko:"오히려",en:"rather / on the contrary",zh:"反而",vi:"ngược lại",note:"오히려 — pivots to a counterintuitive upside.",noteZh:"오히려——转向一个出人意料的正面看法。",noteVi:"오히려 — chuyển hướng sang một góc nhìn tích cực bất ngờ."},{ko:"장기적으로",en:"in the long term",zh:"从长远来看",vi:"về lâu dài",note:"장기적 (long-term, 長期的) — reframes the time horizon.",noteZh:"장기적（长期的，長期的）——重新设定时间视角。",noteVi:"장기적 (dài hạn) — thiết lập lại tầm nhìn thời gian."}],[{ko:"서로 협력하는",en:"to cooperate with each other",zh:"彼此协作",vi:"hợp tác với nhau",note:"협력 (cooperation, 協力) — turns conflict toward collaboration.",noteZh:"협력（协作，協力）——把矛盾引向合作。",noteVi:"협력 (hợp tác) — chuyển hướng xung đột sang hợp tác."},{ko:"공감대를 형성하는",en:"to build common ground",zh:"凝聚共识",vi:"hình thành sự đồng cảm chung",note:"공감대 형성 = forming shared empathy across generations.",noteZh:"공감대 형성 = 在世代之间建立共鸣。",noteVi:"공감대 형성 = xây dựng sự đồng cảm chung giữa các thế hệ."}]],example:{ko:"역으로 보면, 고령화는 오히려 세대가 서로 협력하는 계기가 될 수도 있습니다.",en:"Looked at the other way, aging could actually become an occasion for generations to cooperate.",zh:"反过来看，老龄化反而可能成为各世代彼此协作的契机。",vi:"Nhìn theo chiều ngược lại, tình trạng già hóa dân số ngược lại có thể trở thành cơ hội để các thế hệ hợp tác với nhau."}},{prompt:{ko:"이상적이긴 한데, 현실에서 가능할까요?",en:"That's ideal, but is it realistic?",zh:"这倒是很理想，但现实中可行吗？",vi:"Nghe thì lý tưởng đấy, nhưng liệu có khả thi trong thực tế không?"},template:"물론 쉽지 않지만, {0} 제도가 뒷받침되고 {1} 충분히 {2}.",blanks:[[{ko:"세대 통합을 위한",en:"for generational integration",zh:"促进世代融合的",vi:"hướng tới sự hòa hợp giữa các thế hệ",note:"통합 (integration, 統合) — names a concrete policy aim.",noteZh:"통합（整合、融合，統合）——点出一个具体的政策目标。",noteVi:"통합 (hòa hợp, thống nhất) — nêu ra một mục tiêu chính sách cụ thể."},{ko:"사회 안전망 같은",en:"such as the social safety net",zh:"诸如社会保障网这样的",vi:"như mạng lưới an sinh xã hội",note:"안전망 — grounds the ideal in a real mechanism.",noteZh:"안전망——把理想落到实实在在的机制上。",noteVi:"안전망 (mạng lưới an sinh) — đưa lý tưởng về với một cơ chế thực tế."}],[{ko:"인식이 제고된다면",en:"if awareness is raised",zh:"如果认识得到提高",vi:"nếu nhận thức được nâng cao",note:"제고하다 (to raise/enhance, 提高) — formal for shifting mindsets.",noteZh:"제고하다（提高，提高）——转变观念的正式说法。",noteVi:"제고하다 (nâng cao) — cách nói trang trọng để chỉ sự thay đổi nhận thức."},{ko:"공감대가 자리 잡으면",en:"once common ground takes root",zh:"一旦共识扎根",vi:"một khi sự đồng cảm chung được định hình",note:"자리 잡다 = to become established as a norm.",noteZh:"자리 잡다 = 确立为一种常态。",noteVi:"자리 잡다 = được xác lập trở thành một chuẩn mực."}],[{ko:"실현 가능하다고 봅니다",en:"I believe it's achievable",zh:"我认为是可以实现的",vi:"tôi cho rằng điều đó khả thi",note:"실현 가능 (feasible, 實現可能) — confident, formal close.",noteZh:"실현 가능（可实现、可行，實現可能）——自信而正式的收尾。",noteVi:"실현 가능 (có thể thực hiện được) — lời kết tự tin và trang trọng."},{ko:"해소될 수 있습니다",en:"it can be resolved",zh:"是可以化解的",vi:"có thể được giải tỏa",note:"해소되다 (to be dissolved, 解消) — pairs with 갈등.",noteZh:"해소되다（化解、消除，解消）——与 갈등（矛盾）搭配。",noteVi:"해소되다 (được giải tỏa, tan biến) — thường đi kèm với 갈등 (xung đột)."}]],example:{ko:"물론 쉽지 않지만, 세대 통합을 위한 제도가 뒷받침되고 인식이 제고된다면 충분히 실현 가능하다고 봅니다.",en:"Of course it's not easy, but if institutions for generational integration back it up and awareness is raised, I believe it's entirely achievable.",zh:"当然不容易，但只要有促进世代融合的制度作支撑，加上认识得到提高，我认为完全可以实现。",vi:"Tất nhiên là không dễ, nhưng nếu có thể chế hỗ trợ cho sự hòa hợp giữa các thế hệ và nhận thức được nâng cao, tôi cho rằng hoàn toàn khả thi."}}]},{id:"ko-scn-c2-academic-001",level:"C2",situation:"academic",title:{ko:"논문 심사",en:"Thesis defense",zh:"论文答辩",vi:"Bảo vệ luận văn"},context:{ko:"심사위원의 날카로운 질문에 학술적으로 응대해요",en:"Responding academically to a committee member's sharp questions",zh:"以学术的方式应对评审委员尖锐的提问",vi:"Ứng đáp một cách học thuật trước những câu hỏi sắc bén của hội đồng giám khảo"},turns:[{prompt:{ko:"연구의 독창성을 한 문장으로 정리하면 무엇입니까?",en:"In one sentence, what is the originality of your research?",zh:"用一句话概括，您研究的独创性是什么？",vi:"Nếu tóm gọn trong một câu, tính độc đáo của nghiên cứu này là gì?"},template:"기존 연구가 {0} 변수를, 본 연구는 {1} 규명했다는 점입니다.",blanks:[[{ko:"간과해 온",en:"have overlooked",zh:"一直忽视的",vi:"đã bị bỏ qua",note:"간과하다 = to overlook; positions a gap in the literature.",noteZh:"간과하다＝忽视；指出文献中的空白。",noteVi:"간과하다 = bỏ qua; chỉ ra khoảng trống trong tài liệu nghiên cứu."},{ko:"단편적으로만 다룬",en:"treated only fragmentarily",zh:"只作零散处理的",vi:"chỉ được xử lý một cách rời rạc",note:"단편적 = piecemeal; claims prior work was incomplete.",noteZh:"단편적＝零散、片面；主张既有研究不够完整。",noteVi:"단편적 = rời rạc, phiến diện; cho rằng nghiên cứu trước đây chưa hoàn chỉnh."}],[{ko:"통합적 관점에서",en:"from an integrated perspective",zh:"从整合的视角",vi:"từ góc nhìn tổng hợp",note:"Frames the contribution as a unifying view.",noteZh:"把研究贡献定位为一种整合性的视角。",noteVi:"Định vị đóng góp của nghiên cứu như một góc nhìn mang tính tổng hợp."},{ko:"실증적으로",en:"empirically",zh:"以实证的方式",vi:"một cách thực chứng",note:"실증적 = evidence-based; stresses rigor.",noteZh:"실증적＝基于证据的；强调严谨性。",noteVi:"실증적 = dựa trên bằng chứng; nhấn mạnh tính chặt chẽ."}]],example:{ko:"기존 연구가 간과해 온 변수를, 본 연구는 통합적 관점에서 규명했다는 점입니다.",en:"It is that this study clarifies, from an integrated perspective, a variable that prior research had overlooked.",zh:"在于本研究从整合的视角，阐明了既有研究一直忽视的变量。",vi:"Đó là nghiên cứu này đã làm rõ, từ góc nhìn tổng hợp, một biến số mà các nghiên cứu trước đây đã bỏ qua."}},{prompt:{ko:"그렇다면 표본 수가 적다는 한계는 어떻게 보완하셨습니까?",en:"Then how did you address the limitation of a small sample size?",zh:"那么，样本数量偏少这一局限，您是如何弥补的？",vi:"Vậy thì ngài đã khắc phục hạn chế về cỡ mẫu nhỏ như thế nào?"},template:"타당한 지적이십니다. {0} 한계를 인정하되, {1} 보완하여 신뢰도를 {2}.",blanks:[[{ko:"표본의",en:"of the sample",zh:"样本的",vi:"của mẫu nghiên cứu",note:"Acknowledges the specific weakness head-on.",noteZh:"正面承认这一具体的不足。",noteVi:"Thẳng thắn thừa nhận điểm yếu cụ thể này."},{ko:"일반화의",en:"of generalization",zh:"推广（普遍化）的",vi:"của việc khái quát hóa",note:"Names the deeper methodological concern.",noteZh:"点明更深层的方法论顾虑。",noteVi:"Chỉ rõ mối lo ngại sâu xa hơn về phương pháp luận."}],[{ko:"질적 분석을 병행해",en:"by also conducting qualitative analysis",zh:"同时进行质性分析",vi:"bằng cách đồng thời tiến hành phân tích định tính",note:"병행하다 = to carry out in parallel; a triangulation defense.",noteZh:"병행하다＝并行开展；以多方印证来辩护。",noteVi:"병행하다 = tiến hành song song; biện hộ bằng cách đối chiếu đa chiều."},{ko:"반복 검증을 거쳐",en:"by going through repeated validation",zh:"经过反复验证",vi:"thông qua việc kiểm chứng lặp lại nhiều lần",note:"Replication as a robustness safeguard.",noteZh:"以可重复验证作为稳健性的保障。",noteVi:"Lấy khả năng tái kiểm chứng làm cơ sở bảo đảm tính vững chắc."}],[{ko:"확보하고자 했습니다",en:"sought to secure",zh:"力求加以确保",vi:"đã cố gắng đảm bảo",note:"-고자 하다 = formal 'sought to'; hedged, academic.",noteZh:"-고자 하다＝正式的“力求”；委婉、学术化。",noteVi:"-고자 하다 = 'cố gắng để' mang tính trang trọng; uyển chuyển, học thuật."},{ko:"높이려 노력했습니다",en:"endeavored to raise",zh:"努力加以提升",vi:"đã nỗ lực để nâng cao",note:"Slightly plainer but still formal.",noteZh:"略为朴实，但仍属正式。",noteVi:"Hơi giản dị hơn nhưng vẫn thuộc văn phong trang trọng."}]],example:{ko:"타당한 지적이십니다. 표본의 한계를 인정하되, 질적 분석을 병행해 보완하여 신뢰도를 확보하고자 했습니다.",en:"That is a valid point. While acknowledging the sample's limitation, I sought to secure reliability by complementing it with parallel qualitative analysis.",zh:"您指得很有道理。我承认样本的局限，但通过同时进行质性分析加以弥补，力求确保信度。",vi:"Đó là một nhận xét xác đáng. Tôi thừa nhận hạn chế của mẫu nghiên cứu, nhưng đã cố gắng đảm bảo độ tin cậy bằng cách bổ sung đồng thời phân tích định tính."}},{prompt:{ko:"마지막으로, 이 연구의 후속 과제는 무엇이라고 보십니까?",en:"Finally, what do you see as the follow-up tasks for this research?",zh:"最后，您认为这项研究的后续课题是什么？",vi:"Cuối cùng, ngài xem đâu là những nhiệm vụ nghiên cứu tiếp theo của công trình này?"},template:"{0} 이번 결과를 다양한 맥락에 적용해 {1} 확장하는 것이 과제라고 봅니다.",blanks:[[{ko:"나아가",en:"by extension / furthermore",zh:"更进一步",vi:"hơn nữa",note:"Elevated connective to broaden scope.",noteZh:"文雅的衔接语，用以拓展范围。",noteVi:"Từ nối trang nhã dùng để mở rộng phạm vi."},{ko:"장기적으로는",en:"in the long term",zh:"从长远来看",vi:"về lâu dài",note:"Sets a forward-looking research horizon.",noteZh:"确立前瞻性的研究视野。",noteVi:"Thiết lập tầm nhìn nghiên cứu hướng tới tương lai."}],[{ko:"일반화 가능성을",en:"the possibility of generalization",zh:"推广（普遍化）的可能性",vi:"khả năng khái quát hóa",note:"The natural next step after a limited study.",noteZh:"在有限研究之后自然的下一步。",noteVi:"Bước tiếp theo tự nhiên sau một nghiên cứu còn hạn chế."},{ko:"이론적 함의를",en:"the theoretical implications",zh:"理论层面的意涵",vi:"hàm ý lý thuyết",note:"함의 = implication; signals scholarly ambition.",noteZh:"함의＝意涵；显示出学术上的抱负。",noteVi:"함의 = hàm ý; thể hiện tham vọng học thuật."}]],example:{ko:"나아가 이번 결과를 다양한 맥락에 적용해 일반화 가능성을 확장하는 것이 과제라고 봅니다.",en:"Furthermore, I see the task as extending the generalizability by applying these results across varied contexts.",zh:"更进一步，我认为课题在于将本次结果应用于各种情境，从而拓展其推广的可能性。",vi:"Hơn nữa, tôi cho rằng nhiệm vụ là áp dụng kết quả này vào nhiều bối cảnh khác nhau để mở rộng khả năng khái quát hóa."}}]},{id:"ko-scn-c2-formal-001",level:"C2",situation:"formal",title:{ko:"고위급 협상",en:"High-level negotiation",zh:"高层谈判",vi:"Đàm phán cấp cao"},context:{ko:"격식을 갖춰 까다로운 협상을 풀어 가요",en:"Navigating a delicate negotiation with full formality",zh:"以十足的礼节化解棘手的谈判",vi:"Giải quyết một cuộc đàm phán hóc búa với đầy đủ nghi thức trang trọng"},turns:[{prompt:{ko:"솔직히 말씀드려, 제시하신 조건은 받아들이기 어렵습니다.",en:"Frankly speaking, the terms you've proposed are hard to accept.",zh:"坦率地说，您提出的条件我们很难接受。",vi:"Nói thẳng thắn, các điều kiện mà ngài đề xuất rất khó để chấp nhận."},template:"충분히 이해합니다. 다만 {0} 부분은 {1}, 대안을 함께 {2}.",blanks:[[{ko:"양측의 이해가 상충하는",en:"where both sides' interests conflict",zh:"双方利益相互抵触的",vi:"nơi lợi ích của hai bên xung đột",note:"상충하다 = to clash; names the friction diplomatically.",noteZh:"상충하다＝冲突；委婉地点明分歧所在。",noteVi:"상충하다 = xung đột; khéo léo chỉ ra điểm bất đồng."},{ko:"이견이 좁혀지지 않는",en:"where differences aren't narrowing",zh:"分歧难以缩小的",vi:"nơi những bất đồng chưa được thu hẹp",note:"이견 = differing views; acknowledges the impasse.",noteZh:"이견＝不同意见；承认陷入僵局。",noteVi:"이견 = quan điểm khác biệt; thừa nhận tình trạng bế tắc."}],[{ko:"지금 단정하기보다",en:"rather than concluding now",zh:"与其现在就下定论",vi:"thay vì kết luận ngay bây giờ",note:"단정하다 = to conclude definitively; urges patience.",noteZh:"단정하다＝断然下结论；劝人稍安勿躁。",noteVi:"단정하다 = khẳng định dứt khoát; khuyên nên kiên nhẫn hơn."},{ko:"감정을 앞세우기보다",en:"rather than leading with emotion",zh:"与其感情用事",vi:"thay vì để cảm xúc lấn át",note:"Gently steers the tone back to reason.",noteZh:"温和地把语气引回理性。",noteVi:"Nhẹ nhàng đưa giọng điệu trở lại tính lý trí."}],[{ko:"모색해 보면 어떨까 합니다",en:"I wonder if we might explore",zh:"一起探寻一下，您看如何",vi:"tôi nghĩ chúng ta nên cùng tìm kiếm thử xem sao",note:"모색하다 = to seek out; -면 어떨까 hedges the proposal.",noteZh:"모색하다＝寻求；-면 어떨까 使提议更为委婉。",noteVi:"모색하다 = tìm kiếm; -면 어떨까 làm cho đề xuất trở nên uyển chuyển hơn."},{ko:"강구해 보고자 합니다",en:"I would like to devise",zh:"想设法研拟一下",vi:"tôi muốn tìm cách nghiên cứu đối sách",note:"강구하다 = to work out a measure; formal.",noteZh:"강구하다＝研拟对策；正式用语。",noteVi:"강구하다 = tìm ra biện pháp; cách nói trang trọng."}]],example:{ko:"충분히 이해합니다. 다만 양측의 이해가 상충하는 부분은 지금 단정하기보다, 대안을 함께 모색해 보면 어떨까 합니다.",en:"I fully understand. But rather than settling the points where our interests clash right now, I wonder if we might explore alternatives together.",zh:"我完全理解。只是双方利益相互抵触的部分，与其现在就下定论，不如一起探寻替代方案，您看如何？",vi:"Tôi hoàn toàn hiểu điều đó. Nhưng thay vì kết luận ngay bây giờ về những điểm mà lợi ích hai bên xung đột, tôi nghĩ chúng ta nên cùng tìm kiếm phương án thay thế thử xem sao."}},{prompt:{ko:"그 말씀은 결국 양보할 뜻이 없다는 것 아닙니까?",en:"Doesn't that ultimately mean you have no intention of yielding?",zh:"您这话说到底，不就是没有让步的意思吗？",vi:"Nói như vậy chẳng phải cuối cùng có nghĩa là ngài không có ý định nhượng bộ sao?"},template:"오해가 있으신 듯합니다. {0} 아니라, {1} 선에서 {2} 드리겠다는 뜻입니다.",blanks:[[{ko:"양보의 여지가 없다는 것이",en:"that there's no room to concede",zh:"没有让步的余地",vi:"việc không có chỗ để nhượng bộ",note:"여지 = room/margin; directly addresses the suspicion.",noteZh:"여지＝余地；正面回应对方的疑虑。",noteVi:"여지 = dư địa/khoảng trống; trực tiếp đáp lại mối nghi ngờ của đối phương."},{ko:"원칙만 고수하겠다는 것이",en:"that we'll cling only to principle",zh:"只死守原则",vi:"việc chỉ khăng khăng giữ nguyên tắc",note:"고수하다 = to adhere firmly; reframes the worry.",noteZh:"고수하다＝坚守；重新诠释对方的担忧。",noteVi:"고수하다 = kiên trì giữ vững; diễn giải lại mối lo ngại của đối phương."}],[{ko:"양측이 수용 가능한",en:"acceptable to both parties",zh:"双方都能接受的",vi:"mà cả hai bên đều có thể chấp nhận được",note:"Signals a search for common ground.",noteZh:"表明在寻求双方的共识。",noteVi:"Thể hiện việc đang tìm kiếm điểm chung giữa hai bên."},{ko:"실리를 해치지 않는",en:"without harming substantive interests",zh:"不损害实际利益的",vi:"mà không làm tổn hại đến lợi ích thực chất",note:"실리 = practical benefit; protects the bottom line.",noteZh:"실리＝实际利益；守住底线。",noteVi:"실리 = lợi ích thực tế; bảo vệ giới hạn cuối cùng."}],[{ko:"최대한 조율해",en:"to coordinate as much as possible",zh:"尽最大努力加以协调",vi:"điều chỉnh hết mức có thể",note:"조율하다 = to fine-tune/harmonize; collaborative tone.",noteZh:"조율하다＝调和／协调；合作的语气。",noteVi:"조율하다 = điều hòa/phối hợp; giọng điệu mang tính hợp tác."},{ko:"성의껏 검토해",en:"to review in good faith",zh:"诚意十足地加以研究",vi:"xem xét một cách thành tâm",note:"성의껏 = with sincerity; reassures the counterpart.",noteZh:"성의껏＝尽心诚意地；让对方安心。",noteVi:"성의껏 = hết lòng thành tâm; giúp đối phương yên tâm."}]],example:{ko:"오해가 있으신 듯합니다. 양보의 여지가 없다는 것이 아니라, 양측이 수용 가능한 선에서 최대한 조율해 드리겠다는 뜻입니다.",en:"I think there's a misunderstanding. It's not that there's no room to concede — I mean we'll coordinate as much as possible within terms acceptable to both sides.",zh:"您似乎有所误会。我的意思并不是没有让步的余地，而是会在双方都能接受的范围内尽最大努力加以协调。",vi:"Hình như có sự hiểu lầm nào đó. Không phải là không có chỗ để nhượng bộ, mà ý tôi là chúng tôi sẽ điều chỉnh hết mức có thể trong phạm vi mà cả hai bên đều có thể chấp nhận được."}},{prompt:{ko:"좋습니다. 그렇다면 다음 회의까지 수정안을 마련해 주십시오.",en:"All right. In that case, please prepare a revised proposal by the next meeting.",zh:"好。那么，请在下次会议前准备好修订方案。",vi:"Được rồi. Vậy thì xin hãy chuẩn bị phương án sửa đổi trước cuộc họp tiếp theo."},template:"그렇게 하겠습니다. {0} 신뢰를 바탕으로 {1} 결실을 맺도록 {2}.",blanks:[[{ko:"오늘 쌓은",en:"built today",zh:"今天建立起的",vi:"được xây dựng hôm nay",note:"Credits the progress just made; warm close.",noteZh:"肯定刚刚取得的进展；温暖的收尾。",noteVi:"Ghi nhận tiến triển vừa đạt được; lời kết ấm áp."},{ko:"그간 다져 온",en:"cultivated over time",zh:"这段时间夯实起来的",vi:"đã được vun đắp bấy lâu nay",note:"다지다 = to firm up; nods to a longer relationship.",noteZh:"다지다＝夯实；点到更长久的关系。",noteVi:"다지다 = củng cố vững chắc; ám chỉ mối quan hệ lâu dài hơn."}],[{ko:"상생의",en:"of mutual flourishing",zh:"互利共赢的",vi:"cùng phát triển",note:"상생 = win-win coexistence; aspirational framing.",noteZh:"상생＝共生共赢；带有愿景色彩的表述。",noteVi:"상생 = cùng tồn tại đôi bên cùng có lợi; cách diễn đạt mang tính tầm nhìn."},{ko:"호혜적인",en:"reciprocal",zh:"互惠的",vi:"mang tính hỗ tương",note:"호혜적 = mutually beneficial; formal register.",noteZh:"호혜적＝互惠互利；正式语体。",noteVi:"호혜적 = cùng có lợi cho nhau; văn phong trang trọng."}],[{ko:"만전을 기하겠습니다",en:"I will leave nothing to chance",zh:"定当竭力做到万无一失",vi:"tôi sẽ không để sót bất kỳ điều gì",note:"만전을 기하다 = to make everything watertight; firm pledge.",noteZh:"만전을 기하다＝力求万无一失；坚定承诺。",noteVi:"만전을 기하다 = làm mọi thứ thật kín kẽ; lời cam kết chắc chắn."},{ko:"최선을 다하겠습니다",en:"I will do my utmost",zh:"定当竭尽全力",vi:"tôi sẽ nỗ lực hết mình",note:"Standard but sincere commitment.",noteZh:"标准但真诚的承诺。",noteVi:"Lời cam kết tiêu chuẩn nhưng chân thành."}]],example:{ko:"그렇게 하겠습니다. 오늘 쌓은 신뢰를 바탕으로 상생의 결실을 맺도록 만전을 기하겠습니다.",en:"I will do so. Building on the trust we've established today, I will leave nothing to chance so that we bear win-win fruit.",zh:"我会照办。我们将以今天建立起的信任为基础，竭力做到万无一失，以结出互利共赢的果实。",vi:"Tôi sẽ làm như vậy. Dựa trên niềm tin được xây dựng hôm nay, tôi sẽ không để sót bất kỳ điều gì nhằm gặt hái được thành quả cùng phát triển."}}]}];n.s(["ALL_SCENARIOS_KO",0,t],576626)}]);